// ===== src/checkout/checkout.ts =====
import { Payments } from '../payments/payments';
import { Inventory } from '../inventory/inventory';

export class Checkout {
  constructor(private payments: Payments, private inventory: Inventory) {}

  async submitOrder(cart: Cart): Promise<OrderReceipt> {
    const hold = await this.inventory.reserveStock(cart.lines);
    const charge = await this.payments.capturePayment(cart.total, cart.token);
    if (!charge.ok) {
      await this.inventory.releaseStock(hold);
      throw new Error('payment declined');
    }
    return { orderId: charge.id, reservedAt: hold.at };
  }
}

// ===== src/payments/payments.ts =====
import { PaymentGateway } from './gateway';
import { logger } from '../lib/logger';

export class Payments {
  constructor(private gateway: PaymentGateway) {}

  async capturePayment(amount: number, token: string): Promise<ChargeResult> {
    const idem = token + ':' + amount;
    const res = await this.gateway.sendCharge({ amount, token, idem });
    logger.info('captured', { amount, ok: res.ok });
    return res;
  }

  async refundPayment(chargeId: string, amount: number): Promise<void> {
    await this.gateway.sendCharge({ amount: -amount, ref: chargeId, idem: chargeId });
    logger.info('refunded', { chargeId, amount });
  }
}

// ===== src/payments/gateway.ts =====
import { withRetry } from '../lib/retry';

export class PaymentGateway {
  constructor(private baseUrl: string, private key: string) {}

  async sendCharge(req: ChargeRequest): Promise<ChargeResult> {
    return withRetry(async () => {
      const res = await fetch(this.baseUrl + '/charges', {
        method: 'POST',
        headers: { authorization: 'Bearer ' + this.key },
        body: JSON.stringify(req),
      });
      if (!res.ok) throw Object.assign(new Error('gateway'), { status: res.status });
      return res.json() as Promise<ChargeResult>;
    }, 'sendCharge');
  }
}

// ===== src/inventory/inventory.ts =====
import { db } from '../lib/db';

export class Inventory {
  async reserveStock(lines: CartLine[]): Promise<StockHold> {
    const ids = lines.map((l) => l.sku);
    await db.stock.decrement(ids);
    const at = await db.holds.insert({ ids, status: 'held' });
    return { id: at.id, at: at.created };
  }

  async releaseStock(hold: StockHold): Promise<void> {
    await db.holds.update(hold.id, { status: 'released' });
  }
}

// ===== src/billing/subscriptions.ts =====
import { PaymentGateway } from '../payments/gateway';
import { db } from '../lib/db';

export class Subscriptions {
  constructor(private gateway: PaymentGateway) {}

  async chargeCycle(sub: Subscription): Promise<void> {
    const due = sub.plan.priceCents * sub.seats;
    const discount = sub.coupon ? Math.round(due * sub.coupon.rate) : 0;
    await this.gateway.sendCharge({ amount: due - discount, token: sub.token, idem: sub.cycleId });
    sub.nextBillingAt = Date.now() + sub.plan.intervalMs;
    await db.subscriptions.update(sub.id, { nextBillingAt: sub.nextBillingAt });
  }

  async cancel(sub: Subscription, reason: string): Promise<void> {
    sub.status = 'cancelled';
    sub.cancelledAt = Date.now();
    sub.cancelReason = reason;
    await db.subscriptions.update(sub.id, sub);
  }

  async proration(sub: Subscription, newSeats: number): Promise<number> {
    const remaining = sub.nextBillingAt - Date.now();
    const perSeat = sub.plan.priceCents * (remaining / sub.plan.intervalMs);
    return Math.round(perSeat * (newSeats - sub.seats));
  }
}

// ===== src/billing/payouts.ts =====
import { PaymentGateway } from '../payments/gateway';
import { db } from '../lib/db';

export class Payouts {
  constructor(private gateway: PaymentGateway) {}

  async disburseFunds(account: SellerAccount): Promise<void> {
    const net = account.balanceCents - account.feeCents;
    if (net <= 0) throw new Error('nothing to disburse');
    await this.gateway.sendCharge({ amount: -net, ref: account.id, idem: account.payoutId });
    account.balanceCents = account.feeCents;
    await db.payouts.insert({ accountId: account.id, net, at: Date.now() });
  }

  async schedule(account: SellerAccount, when: number): Promise<void> {
    const existing = await db.payouts.pending(account.id);
    if (existing) await db.payouts.update(existing.id, { scheduledAt: when });
    else await db.payouts.insert({ accountId: account.id, scheduledAt: when, status: 'pending' });
  }

  async statement(account: SellerAccount, month: string): Promise<Statement> {
    const rows = await db.payouts.forMonth(account.id, month);
    const total = rows.reduce((a, r) => a + r.net, 0);
    return { account: account.id, month, total, count: rows.length };
  }
}

// ===== src/notify/notifier.ts =====
import { db } from '../lib/db';

export class Notifier {
  async deliverEmail(job: EmailJob): Promise<void> {
    const tpl = await db.templates.get(job.template);
    const html = render(tpl, job.vars);
    await sendSmtp(job.to, tpl.subject, html);
    await db.outbox.insert({ to: job.to, sentAt: Date.now(), template: job.template });
  }

  async deliverSms(job: SmsJob): Promise<void> {
    const body = truncate(render(job.template, job.vars), 160);
    await sendSms(job.phone, body);
    await db.outbox.insert({ to: job.phone, sentAt: Date.now(), channel: 'sms' });
  }

  async retryFailed(since: number): Promise<number> {
    const failed = await db.outbox.failedSince(since);
    for (const row of failed) await this.deliverEmail(row.job);
    return failed.length;
  }
}

// ===== src/obs/metrics.ts =====
export class Metrics {
  private buf: Sample[] = [];

  recordEvent(name: string, value: number, tags: Tags): void {
    this.buf.push({ name, value, tags, ts: Date.now() });
    if (this.buf.length >= 500) this.flush();
  }

  gauge(name: string, value: number, tags: Tags): void {
    const existing = this.buf.findIndex((s) => s.name === name);
    if (existing >= 0) this.buf[existing] = { name, value, tags, ts: Date.now() };
    else this.buf.push({ name, value, tags, ts: Date.now() });
  }

  private flush(): void {
    const batch = this.buf.splice(0);
    ship(batch);
  }
}

// ===== src/config/loader.ts =====
import { z } from 'zod';

const schema = z.object({
  gatewayUrl: z.string().url(),
  retryMax: z.coerce.number().default(5),
  cacheTtlMs: z.coerce.number().default(60_000),
});

export class ConfigLoader {
  loadSettings(env: NodeJS.ProcessEnv): AppConfig {
    const parsed = schema.safeParse({
      gatewayUrl: env.GATEWAY_URL,
      retryMax: env.RETRY_MAX,
      cacheTtlMs: env.CACHE_TTL_MS,
    });
    if (!parsed.success) throw new Error('bad config: ' + parsed.error.message);
    return parsed.data;
  }

  redactForLog(cfg: AppConfig): Partial<AppConfig> {
    const { gatewayUrl, retryMax } = cfg;
    return { gatewayUrl, retryMax };
  }
}

// ===== src/audit/audit.ts =====
import { db } from '../lib/db';

export class AuditTrail {
  async appendEntry(actor: string, action: string, meta: Meta): Promise<void> {
    const prev = await db.audit.latest();
    const hash = chain(prev?.hash, actor, action);
    await db.audit.insert({ actor, action, meta, hash, at: Date.now() });
  }

  async verifyChain(): Promise<boolean> {
    const rows = await db.audit.all();
    let prev: string | undefined;
    for (const row of rows) {
      if (chain(prev, row.actor, row.action) !== row.hash) return false;
      prev = row.hash;
    }
    return true;
  }
}

// ===== src/cache/session.ts =====
export class SessionCache {
  private store = new Map<string, { v: Session; exp: number }>();
  constructor(private ttlMs: number) {}

  lookupSession(token: string): Session | undefined {
    const hit = this.store.get(token);
    if (!hit || hit.exp < Date.now()) {
      this.store.delete(token);
      return undefined;
    }
    return hit.v;
  }

  putSession(token: string, session: Session): void {
    this.store.set(token, { v: session, exp: Date.now() + this.ttlMs });
  }

  evictExpired(): number {
    const now = Date.now();
    let n = 0;
    for (const [k, e] of this.store) if (e.exp < now) { this.store.delete(k); n += 1; }
    return n;
  }
}
